    /// at 6886 else-if MatchOptWithParam("oeuler", ...) -- strncmp
    /// "oeuler" vs "openif" 'e'!='p' at index 1 -- false. Arm 4 at
    /// 6891 else-if MatchOptWithParam("openif", "openif 1,2", ...):
    /// strncmp matches 6B; pch[6]=' '; param="1,2"; returns true.
    /// </para>
    ///
