    /// server emits when admin-tier double-slash <c>//editfaction</c>
    /// arrives with no argument. Matcher at PlayerConnection.cpp:4892
    /// (case-'e' arm of the admin-tier switch opened at 4724) -- NO-INLINE-
    /// GUARD pattern (outer GM gate at 4716 is the only AdminLevel check
    /// on the dispatch path). FIRST admin-tier case-'e' pin; case-'e'
    /// admin-tier now SINGLE-PINNED.
    /// </summary>
    private const string MissingArgEditfactionLiteral = "Missing arg for option editfaction";

    /// <summary>
    /// Wave 212 sibling-arm-pinning hardening (+0 ratchet): pins the
    /// 38-byte wire-shape of the single 0x001D MESSAGE_STRING reply to
    /// admin-tier double-slash <c>//editfaction</c> (NO param). Wave 212
    /// opens admin-tier case-'e' to SINGLE-PINNED status.
    ///
    /// <para>
    /// Outer gate at 4716 (<c>Msg[0]=='/' &amp;&amp; Msg[1]=='/' &amp;&amp;
    /// AdminLevel() >= GM</c>) admits the dispatch; cli_test status=100
    /// satisfies GM=50. Switch at 4724 jumps on *pch -> case-'e' opens at
    /// 4890. case-'e' has two arms (BOTH plain `if`, not else-if):
    /// MatchOptWithParam("editfaction", pch) at 4892 matches 11B vs 11B.
    /// NO inline AdminLevel guard. param=NULL so the body branch is not
    /// reached; allowNoParams=false (default) fires the 4548 ERROR fork:
    /// "Missing arg for option editfaction" COLOR=5. The second arm
    /// MatchOptWithParam("editplayerfaction", pch="editfaction") -- 17B
    /// vs 11B; strncmp byte 4 'p' vs 'f' MISMATCH -> silent FALSE. case-'e'
    /// breaks. NET RESULT: ONE emit.
    /// </para>
    ///
